"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[477],{10:function(n){n.exports=JSON.parse('{"blogPosts":[{"id":"mysql-event-scheduler","metadata":{"permalink":"/blog/mysql-event-scheduler","source":"@site/blog\\\\2022-06-09-MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler).md","title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","description":"\u57fa\u4e8e MySQL 5.7\uff0c\u5b98\u65b9\u6587\u6863\u5730\u5740\uff1a","date":"2022-06-09T00:00:00.000Z","formattedDate":"2022\u5e746\u67089\u65e5","tags":[{"label":"MySQL","permalink":"/blog/tags/my-sql"}],"truncated":false,"authors":[],"frontMatter":{"slug":"mysql-event-scheduler","title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","tags":["MySQL"]},"nextItem":{"title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","permalink":"/blog/springboot-config-priority"}},"content":"\u57fa\u4e8e MySQL 5.7\uff0c\u5b98\u65b9\u6587\u6863\u5730\u5740\uff1a\\r\\n\\r\\nCREATE\uff1a[https://dev.mysql.com/doc/refman/5.7/en/create-event.html](https://dev.mysql.com/doc/refman/5.7/en/create-event.html)\\r\\n\\r\\nALTER EVENT: [https://dev.mysql.com/doc/refman/5.7/en/alter-event.html](https://dev.mysql.com/doc/refman/5.7/en/alter-event.html)\\r\\n\\r\\n## \u524d\u7f6e\u6761\u4ef6\\r\\n\\r\\n\u5728\u521b\u5efaEVENT\u4e4b\u524d\uff0c\u9700\u8981\u5148\u786e\u8ba4 `Event Scheduler` \u529f\u80fd\u662f\u5426\u5f00\u542f\u3002[https://dev.mysql.com/doc/refman/5.7/en/events-configuration.html](https://dev.mysql.com/doc/refman/5.7/en/events-configuration.html)\\r\\n\\r\\n```SQL\\r\\n-- \u67e5\u770b\u5f00\u542f\u72b6\u6001 \\r\\nSHOW GLOBAL VARIABLES like \'%event_scheduler%\'; \\r\\n-- \u5f00\u542f \\r\\nSET GLOBAL event_scheduler = ON; \\r\\n-- \u5173\u95ed \\r\\nSET GLOBAL event_scheduler = OFF;\\r\\n```\\r\\n\\r\\n\\r\\n## CREATE Event\\r\\n\\r\\n\u8bed\u6cd5\\r\\n\\r\\n```SQL\\r\\n\\r\\nCREATE\\r\\n    [DEFINER = user]\\r\\n    EVENT\\r\\n    [IF NOT EXISTS]\\r\\n    event_name\\r\\n    ON SCHEDULE schedule\\r\\n    [ON COMPLETION [NOT] PRESERVE]\\r\\n    [ENABLE | DISABLE | DISABLE ON SLAVE]\\r\\n    [COMMENT \'string\']\\r\\n    DO event_body;\\r\\n\\r\\nschedule: {\\r\\n    AT timestamp [+ INTERVAL interval] ...\\r\\n  | EVERY interval\\r\\n    [STARTS timestamp [+ INTERVAL interval] ...]\\r\\n    [ENDS timestamp [+ INTERVAL interval] ...]\\r\\n}\\r\\n\\r\\ninterval:\\r\\n    quantity {YEAR | QUARTER | MONTH | DAY | HOUR | MINUTE |\\r\\n              WEEK | SECOND | YEAR_MONTH | DAY_HOUR | DAY_MINUTE |\\r\\n              DAY_SECOND | HOUR_MINUTE | HOUR_SECOND | MINUTE_SECOND}\\r\\n              \\r\\n```\\r\\n\\r\\n-   DEFINER\uff0c\u5b9a\u4e49\u7528\u6237\\r\\n-   schedule\uff0c\u6267\u884c\u8ba1\u5212\uff0c\u6709\u4e24\u79cd\u65b9\u5f0f\uff1a`ON SCHEDULE AT CURRENT_TIMESTAMP + INTERVAL 1 HOUR` \u6216 `EVERY 1 DAY STARTS CURRENT_TIMESTAMP`\\r\\n-   `ON COMPLETION [NOT] PRESERVE`, \u9ed8\u8ba4EVENT\u8fc7\u671f\u540e\u5c31\u4e22\u5f03(NOT PRESERVE)\uff0c\u53ef\u901a\u8fc7 `ON COMPLETION PRESERVE` \u7533\u660e\u8fc7\u671f\u540e\u4ecd\u7136\u4fdd\u7559\uff0c\u4e00\u822c\u7528\u4e8e\u5230\u4e86\u65f6\u95f4\u70b9\uff0c\u4e0a\u4e00\u4e2a\u4efb\u52a1\u8fd8\u6ca1\u6709\u6267\u884c\u5b8c\u6210\uff0c\u5f53\u524d\u7684\u8fd9\u4e2a\u4efb\u52a1\u662f\u76f4\u63a5\u4e22\u5f03\uff0c\u8fd8\u662f\u7b49\u4e0a\u4e2a\u4efb\u52a1\u6267\u884c\u5b8c\u6210\u540e\u518d\u6267\u884c\\r\\n-   `[ENABLE | DISABLE | DISABLE ON SLAVE]`, \u7533\u660e\u4ece\u5e93\uff0c\u4e00\u822c\u4e0d\u7533\u660e\\r\\n\\r\\n\u5bf9\u4e8eDO\u64cd\u4f5c\u4e2d\u6bd4\u8f83\u590d\u6742\u7684\u6267\u884c\u8ba1\u5212\uff0c\u53ef\u4ee5\u901a\u8fc7\u4ee5\u4e0b2\u79cd\u65b9\u5f0f\\r\\n\\r\\n-   `DO` \u4e2d\u7533\u660e `BEGIN` \u548c `END`\\r\\n-   \u6539\u6210\u8c03\u7528\u50a8\u5b58\u8fc7\u7a0b\u7684\u65b9\u5f0f\\r\\n\\r\\n## \u793a\u4f8b\\r\\n\\r\\n**1. \u5b98\u65b9\u793a\u4f8b**\\r\\n\\r\\n```SQL\\r\\n-- \u793a\u4f8b\uff1a\u6bcf\u5c0f\u65f6\u66f4\u65b0\u4e00\u6b21\\r\\nCREATE EVENT myevent\\r\\n    ON SCHEDULE AT CURRENT_TIMESTAMP + INTERVAL 1 HOUR\\r\\n    DO\\r\\n      UPDATE myschema.mytable SET mycol = mycol + 1;\\r\\n```\\r\\n\\r\\n```SQL\\r\\ndelimiter $$\\r\\n\\r\\nCREATE EVENT e\\r\\n    ON SCHEDULE\\r\\n      EVERY 5 SECOND\\r\\n    DO\\r\\n      BEGIN\\r\\n        DECLARE v INTEGER;\\r\\n        -- \u8fd9\u91cc\u7684 BEGIN END\uff0c\u4e0d\u6e05\u695a\u662f\u5426\u662f\u7b14\u8bef\\r\\n        DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN END;\\r\\n\\r\\n        SET v = 0;\\r\\n\\r\\n        WHILE v < 5 DO\\r\\n          INSERT INTO t1 VALUES (0);\\r\\n          UPDATE t2 SET s1 = s1 + 1;\\r\\n          SET v = v + 1;\\r\\n        END WHILE;\\r\\n    END $$\\r\\n\\r\\ndelimiter ;\\r\\n```\\r\\n\\r\\n```SQL\\r\\nCREATE EVENT e_call_myproc\\r\\n    ON SCHEDULE\\r\\n      AT CURRENT_TIMESTAMP + INTERVAL 1 DAY\\r\\n    DO CALL myproc(5, 27);\\r\\n```\\r\\n\\r\\n\\r\\n**2. \u5de5\u7a0b\u5b9e\u8df5**\\r\\n\\r\\n\u6eda\u52a8\u5220\u9664\u5386\u53f2\u6570\u636e\uff0c\u5220\u9664\u5f53\u524d\u65f6\u95f4\u5f80\u524d15\u7684\u5386\u53f2\u6570\u636e\u3002\u6ca1\u6709\u8bbe\u7f6e `ON COMPLETION PRESERVE` \u7684\u539f\u56e0\u662f\uff0c\u5982\u679c\u6f0f\u6389\u4e00\u6b21\u5bf9\u4e8b\u4ef6\u672c\u8eab\u5f71\u54cd\u4e0d\u5927\u3002\\r\\n\\r\\n```SQL\\r\\n-- CREATE\\r\\ndelimiter $$\\r\\n\\r\\nCREATE EVENT IF NOT EXISTS records_interval_clear\\r\\n    ON SCHEDULE\\r\\n      EVERY 1 DAY STARTS \'2021-08-06 01:00:00\'        \\r\\n    DO\\r\\n      BEGIN\\r\\n        DECLARE v_time BIGINT(20) DEFAULT 0;\\r\\n        -- \u5f53\u524d\u65e5\u671f\u5f80\u524d15\u5929\\r\\n        SET v_time = (SELECT UNIX_TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL 15 DAY)) * 1000);\\r\\n        DELETE FROM t_history WHERE create_time < v_time;\\r\\n       END $$\\r\\n\\r\\ndelimiter ;\\r\\n```\\r\\n\\r\\n## \u5176\u4ed6\u547d\u4ee4\\r\\n\\r\\n\u67e5\u770b\u6267\u884c\u8ba1\u5212\uff1a\\r\\n\\r\\n```SQL\\r\\nSELECT * FROM INFORMATION_SCHEMA.events;\\r\\n```\\r\\n\\r\\n\\r\\n\u7981\u7528 `EVENT`\\r\\n\\r\\n```SQL\\r\\nALTER EVENT myevent DISABLE;\\r\\n```\\r\\n\\r\\nDROP\\r\\n\\r\\n```SQL\\r\\nDROP EVENT [IF EXISTS] event_name\\r\\n```\\r\\n\\r\\n## \u6ce8\u610f\\r\\n\\r\\n1. \u5728\u5b9a\u65f6\u4efb\u52a1\u5f00\u542f\u524d\uff0c\u9700\u8981\u9884\u4f30\u4e0b\u7b2c\u4e00\u6b21\u6267\u884c\u65f6\u5220\u9664\u7684\u5386\u53f2\u6570\u636e\u91cf\uff0c\u4ee5\u514d\u56e0\u5220\u9664\u6570\u636e\u91cf\u8fc7\u591a\u5bfc\u81f4\u6570\u636e\u5e93\u5361\u6b7b\u7684\u60c5\u51b5\uff0c\u5efa\u8bae\u7b2c\u4e00\u6b21\u5148\u624b\u52a8\u5220\u9664\u5386\u53f2\u6570\u636e\\r\\n2. \u5220\u9664\u5927\u8868\u540e\uff0c\u6570\u636e\u5e93\u7684\u5b58\u50a8\u7a7a\u95f4\u5927\u5c0f\u4e0d\u4f1a\u6539\u53d8\uff0c\u9700\u8981\u901a\u8fc7 `optimize table` \u8bed\u53e5\u91ca\u653e\u8868\u7a7a\u95f4\uff0c\u540e\u7eed\u4f18\u5316\u53ef\u53c2\u8003\uff1a[https://help.aliyun.com/document_detail/41720.html](https://help.aliyun.com/document_detail/41720.html) \u6216 \u78c1\u76d8\u788e\u7247\u65e0\u9501\u8868\u7a7a\u95f4\u6e05\u7406\u963f\u91cc\u4e91\u6587\u6863\uff1a[https://help.aliyun.com/document_detail/128340.html](https://help.aliyun.com/document_detail/128340.html)"},{"id":"springboot-config-priority","metadata":{"permalink":"/blog/springboot-config-priority","source":"@site/blog\\\\2022-05-08-SpringBoot\u4e2d\u914d\u7f6e\u6587\u4ef6\u4f18\u5148\u7ea7.md","title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","description":"\u5728\u5f00\u53d1\u8fc7\u7a0b\u4e2d\uff0c\u4e0d\u77e5\u9053\u6709\u6ca1\u6709\u8fd9\u6837\u7684\u7ecf\u5386\uff0c\u9879\u76ee\u5b9e\u9645\u8bfb\u53d6\u7684\u914d\u7f6e\u4fe1\u606f\u6709\u65f6\u5019\u603b\u662f\u4e0e\u9884\u671f\u4e0d\u7b26\uff0c\u4eca\u5929\u5c31\u6765\u7814\u7a76\u4e0b SpringBoot \u8bfb\u53d6\u914d\u7f6e\u6587\u4ef6\u987a\u5e8f\u3002","date":"2022-05-08T00:00:00.000Z","formattedDate":"2022\u5e745\u67088\u65e5","tags":[{"label":"SpringBoot","permalink":"/blog/tags/spring-boot"},{"label":"config","permalink":"/blog/tags/config"}],"truncated":false,"authors":[],"frontMatter":{"slug":"springboot-config-priority","title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","tags":["SpringBoot","config"]},"prevItem":{"title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","permalink":"/blog/mysql-event-scheduler"},"nextItem":{"title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","permalink":"/blog/jvm-dump-file-analysis-experience"}},"content":"\u5728\u5f00\u53d1\u8fc7\u7a0b\u4e2d\uff0c\u4e0d\u77e5\u9053\u6709\u6ca1\u6709\u8fd9\u6837\u7684\u7ecf\u5386\uff0c\u9879\u76ee\u5b9e\u9645\u8bfb\u53d6\u7684\u914d\u7f6e\u4fe1\u606f\u6709\u65f6\u5019\u603b\u662f\u4e0e\u9884\u671f\u4e0d\u7b26\uff0c\u4eca\u5929\u5c31\u6765\u7814\u7a76\u4e0b `SpringBoot` \u8bfb\u53d6\u914d\u7f6e\u6587\u4ef6\u987a\u5e8f\u3002\\r\\n\\r\\n## \u4e00\u3001SpringBoot \u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7\\r\\n\\r\\n[SpringBoot\u5b98\u65b9\u6587\u6863](https://docs.spring.io/spring-boot/docs/2.2.9.RELEASE/reference/htmlsingle/#boot-features-external-config)\u8bf4\u660e\u4e86\u52a0\u8f7d\u7684\u987a\u5e8f\u5982\u4e0b\uff0c\u8d8a\u9760\u524d\u4f18\u5148\u7ea7\u8d8a\u9ad8\u3002\\r\\n\\r\\n>Spring Boot uses a very particular\xa0`PropertySource`\xa0order that is designed to allow sensible overriding of values. Properties are considered in the following order\\r\\n\\r\\n```text  \\r\\n\\r\\n1. \u5f00\u53d1\u8005\u5de5\u5177 Devtools \u5168\u5c40\u914d\u7f6e\u53c2\u6570\uff1b  \\r\\n\\r\\n2. \u5355\u5143\u6d4b\u8bd5\u4e0a\u7684 [@TestPropertySource](mailto:@TestPropertySource)` \u6ce8\u89e3\u6307\u5b9a\u7684\u53c2\u6570;  \\r\\n\\r\\n3. \u5355\u5143\u6d4b\u8bd5\u4e0a\u7684 [@SpringBootTest](mailto:@SpringBootTest)` \u6ce8\u89e3\u6307\u5b9a\u7684\u53c2\u6570\uff1b  \\r\\n\\r\\n4. \u547d\u4ee4\u884c\u6307\u5b9a\u7684\u53c2\u6570\uff0c\u5982 java -jar springboot.jar --name=\\"xxx\\"\uff1b  \\r\\n\\r\\n5. \u547d\u4ee4\u884c\u4e2d\u7684 SPRING_APPLICATION_JSON \u6307\u5b9a\u53c2\u6570, \u5982 java -Dspring.application.json=\'{\\"name\\":\\"xxx\\"}\' -jar springboot.jar  \\r\\n\\r\\n6. ServletConfig\u521d\u59cb\u5316\u53c2\u6570\uff1b  \\r\\n\\r\\n7. ServletContext\u521d\u59cb\u5316\u53c2\u6570\uff1b  \\r\\n\\r\\n8. JNDI\u53c2\u6570\uff08\u5982 java:comp/env/spring.application.json\uff09\uff1b  \\r\\n\\r\\n9. Java\u7cfb\u7edf\u53c2\u6570\uff08\u6765\u6e90\uff1aSystem.getProperties()\uff09\uff1b  \\r\\n\\r\\n10. \u64cd\u4f5c\u7cfb\u7edf\u73af\u5883\u53d8\u91cf\u53c2\u6570\uff1b  \\r\\n\\r\\n11. RandomValuePropertySource \u968f\u673a\u6570\uff0c\u4ec5\u5339\u914d\uff1aramdom.*\uff1b  \\r\\n\\r\\n12. JAR\u5305\u5916\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application-{profile}.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n13. JAR\u5305\u91cc\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application-{profile}.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n14. JAR\u5305\u5916\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n15. JAR\u5305\u91cc\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n16. @Configuration (mailto:@Configuration)\u914d\u7f6e\u6587\u4ef6\u4e0a @PropertySource(mailto:@PropertySource) \u6ce8\u89e3\u52a0\u8f7d\u7684\u53c2\u6570\uff1b  \\r\\n\\r\\n17. \u9ed8\u8ba4\u53c2\u6570\uff08\u901a\u8fc7 SpringApplication.setDefaultProperties \u6307\u5b9a\uff09\uff1b  \\r\\n\\r\\n\\r\\n```\\r\\n\\r\\n\u8fd9\u91cc\u6211\u4eec\u53ea\u5bf9\u6bd4\u5e38\u7528\u7684\u51e0\u4e2a\u5730\u65b9\u7684\u914d\u7f6e\u4f18\u5148\u7ea7\uff1a\\r\\n\\r\\n\u547d\u4ee4\u884c\u53c2\u6570 > JAR\u5305\u5916\u9762\u7684 `application-{profile}.properties` > JAR\u5305\u5185\u7684 `application-{profile}.properties` > JAR\u5305\u5916\u7684 `application.properties` > JAR\u5305\u5185\u7684 `application.properties`\\r\\n\\r\\n\\r\\n\u8fd9\u6837\u53ef\u80fd\u4e0d\u592a\u76f4\u89c2\uff0c\u800c\u4e14\u6709\u7684\u9879\u76ee\u4f1a\u5c06 application.properties \u6587\u4ef6\u653e\u5728config\u6587\u4ef6\u5939\u5185\uff0c\u4e8e\u662f\u8fdb\u4e00\u6b65\u5bf9\u6bd4\u4e86\u8fd9\u4e24\u4e2a\u4f4d\u7f6e\u7684\u4f18\u5148\u7ea7\uff0c\u7ed3\u679c\u5982\u4e0b\\r\\n\\r\\n`SpringBoot` \u5e94\u7528\u7a0b\u5e8f\u5728\u542f\u52a8\u65f6\u4f1a\u9075\u5faa\u4ee5\u4e0b\u987a\u5e8f\u8fdb\u884c\u52a0\u8f7d\u914d\u7f6e\u6587\u4ef6  \\r\\n1. \u7c7b\u8def\u5f84\u4e0b\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n2. \u7c7b\u8def\u5f84\u5185`config`\u5b50\u76ee\u5f55\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n3. \u9879\u76ee\u6839\u76ee\u5f55\u4e0b\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n4. \u9879\u76ee\u6839\u76ee\u5f55\u4e0b`config`\u5b50\u76ee\u5f55\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n  \\r\\n```text  \\r\\n. project-sample  \\r\\n\u251c\u2500\u2500 config  \\r\\n\u2502   \u251c\u2500\u2500 application.yml \uff084\uff09  \\r\\n\u2502   \u2514\u2500\u2500 src/main/resources  \\r\\n|   \u2502   \u251c\u2500\u2500 application.yml \uff081\uff09  \\r\\n|   \u2502   \u2514\u2500\u2500 config  \\r\\n|   |   \u2502   \u251c\u2500\u2500 application.yml \uff082\uff09  \\r\\n\u251c\u2500\u2500 application.yml \uff083\uff09  \\r\\n  \\r\\n\u6ce8\uff1asrc/main/resources\u4e0b\u7684\u914d\u7f6e\u6587\u4ef6\u5728\u9879\u76ee\u7f16\u8bd1\u65f6\uff0c\u4f1a\u653e\u5728target/classes\u4e0b  \\r\\n```  \\r\\n\\r\\n**\u542f\u52a8\u65f6\u52a0\u8f7d\u914d\u7f6e\u6587\u4ef6\u987a\u5e8f\uff1a`1 -> 2 -> 3 -> 4`\uff0c\u4f18\u5148\u7ea7 `4 > 3 > 2 > 1`**\\r\\n\\r\\n\u6ce8\u610f\uff1a  \\r\\n- \u5982\u679c\u5728`IDEA`\u4e2d\u662f\u591a `module` \u9879\u76ee\uff0c3 \u548c 4 \u7684\u4f4d\u7f6e\u662f\u6307\u7684\u662f\u9879\u76ee\u6839\u76ee\u5f55\u4e0b\u7684\u4f4d\u7f6e  \\r\\n- \u5f53 .properties \u548c .yml \u6587\u4ef6\u540c\u65f6\u5b58\u5728\u65f6\uff0c.properties\u4f1a\u5931\u6548\uff0c.yml\u4f1a\u8d77\u4f5c\u7528\u3002  \\r\\n  \\r\\n![](http://file.huhan.tech/images/202205291130509.png)\\r\\n\\r\\n\\r\\n## \u4e8c\u3001bootstrap.yml\u914d\u7f6e\u6587\u4ef6\\r\\n\\r\\n\u5728 `SpringCloud` \u7684\u9879\u76ee\u4e2d\uff0c\u6211\u4eec\u5e38\u5e38\u4f1a\u78b0\u5230\u53e6\u5916\u4e00\u4e2a\u914d\u7f6e\u6587\u4ef6 `bootstrap.yml`\u3002\u8fd9\u4e2a\u914d\u7f6e\u6587\u4ef6\u4e3b\u8981\u662f\u7528\u4e8e\u5e94\u7528\u7a0b\u5e8f\u4e0a\u4e0b\u6587\u7684\u5f15\u5bfc\u9636\u6bb5\uff0c\u8be5\u914d\u7f6e\u6587\u4ef6\u7684\u52a0\u8f7d\u662f\u5728 `application.yml` \u4e4b\u524d\u3002\\r\\n\\r\\nbootstrap.yml \u548c application.yml \u6587\u4ef6\u7684\u533a\u522b\u53ef\u53c2\u8003\uff1a[What is the difference between putting a property on application.yml or bootstrap.yml in spring boot](https://stackoverflow.com/questions/32997352/what-is-the-difference-between-putting-a-property-on-application-yml-or-bootstra)\\r\\n\\r\\n\u5728 SpringCloud \u4e2d\u6709\u4e24\u79cd\u4e0a\u4e0b\u6587\uff0c\u4e00\u79cd\u662f bootstrap, \u53e6\u5916\u4e00\u79cd\u662f application, bootstrap \u662f\u5e94\u7528\u7a0b\u5e8f\u7684\u7236\u4e0a\u4e0b\u6587\u3002\u5b98\u65b9\u7684\u539f\u8bdd\u662f [A Spring Cloud application operates by creating a\xa0\u201cbootstrap\u201d\xa0context, which is a parent context for the main application](https://cloud.spring.io/spring-cloud-commons/multi/multi__spring_cloud_context_application_context_services.html#_the_bootstrap_application_context)\u3002\\r\\n\\r\\n`bootstrap.yml`\u914d\u7f6e\u6587\u4ef6\u7684\u4f7f\u7528\u573a\u666f\uff1a\\r\\n- \u4f7f\u7528\u914d\u7f6e\u4e2d\u5fc3\u65f6\uff0c\u8fd9\u65f6\u9700\u8981\u5728bootstrap\u914d\u7f6e\u6587\u4ef6\u4e2d\u6dfb\u52a0\u8fde\u63a5\u5230\u914d\u7f6e\u4e2d\u5fc3\u7684\u4fe1\u606f\uff0c\u6765\u52a0\u8f7d\u5916\u90e8\u914d\u7f6e\u4e2d\u5fc3\u7684\u914d\u7f6e\u4fe1\u606f\\r\\n- \u4e00\u4e9b\u56fa\u5b9a\u7684\u4e0d\u80fd\u88ab\u8986\u76d6\u7684\u5c5e\u6027\\r\\n- \u4e00\u4e9b\u52a0\u5bc6/\u89e3\u5bc6\u7684\u4fe1\u606f\\r\\n\\r\\n\u9879\u76ee\u4e2d `bootstrap.yml` \u793a\u4f8b\\r\\n\\r\\n```yml\\r\\n\\r\\nspring:\\r\\n  application:\\r\\n    name: \\r\\n  profiles:\\r\\n    active: local\\r\\n  cloud:\\r\\n    nacos:\\r\\n      # \u8fdc\u7a0b\u914d\u7f6e\\r\\n      config:\\r\\n        server-addr: \\r\\n        namespace: \\r\\n        group: ${spring.profiles.active}\\r\\n        file-extension: yml\\r\\n      # \u670d\u52a1\u53d1\u73b0\\r\\n      discovery:\\r\\n        server-addr: \\r\\n        namespace: \\r\\n        group: ${spring.profiles.active}\\r\\n\\r\\n```\\r\\n\\r\\n\\r\\n## \u4e09\u3001\u914d\u7f6e\u4e2d\u5fc3\u7684\u914d\u7f6e\\r\\n\\r\\n\u5728 `SpringCloud` \u9879\u76ee\u4e2d\uff0c\u6211\u4eec\u7684\u914d\u7f6e\u5e38\u7531\u914d\u7f6e\u4e2d\u5fc3\u8fdb\u884c\u7edf\u4e00\u7ba1\u7406\uff0c\u8fd9\u5c31\u6d89\u53ca\u5230\u672c\u5730\u4e0e\u8fdc\u7a0b\u914d\u7f6e\u6587\u4ef6\u7684\u4f18\u5148\u7ea7\u95ee\u9898\u3002\u8fd9\u91cc\u53ea\u8bf4\u660e\u9047\u5230\u8fc7\u7684\u4e24\u79cd: SpringCloud Config \u548c Nacos\u3002\\r\\n\\r\\n1. SpringCloud Config\\r\\n\\r\\nSpringCloud Config \u4e2d\u7684\u8fdc\u7a0b\u914d\u7f6e\uff0c\u9ed8\u8ba4\u662f\u65e0\u6cd5\u88ab\u672c\u5730\u8986\u76d6\uff0c\u5982\u679c\u9700\u8981\u672c\u5730\u914d\u7f6e\u8986\u76d6\u8fdc\u7a0b\u914d\u7f6e\uff0c\u9700\u8981\u5728\u8fdc\u7a0b\u505a\u5982\u4e0b\u914d\u7f6e\uff1a\\r\\n\\r\\n```yml\\r\\nspring:  \\r\\n  cloud:  \\r\\n    config:  \\r\\n      allowOverride: true  \\r\\n      overrideNone: true  \\r\\n      overrideSystemProperties: false\\r\\n```\\r\\n\\r\\n\u4e0a\u9762\u7684\u8bf4\u6cd5\u53ef\u4ee5\u5728\u5982\u4e0b\u94fe\u63a5\u4e2d\u5f97\u5230\u9a8c\u8bc1\uff1a\\r\\nhttps://cloud.spring.io/spring-cloud-commons/multi/multi__spring_cloud_context_application_context_services.html#overriding-bootstrap-properties\\r\\n\\r\\n2. Nacos\\r\\n\\r\\nNacos\u4e2d\u7684\u8fdc\u7a0b\u914d\u7f6e\uff0c\u4f3c\u4e4e\u4e0d\u652f\u6301\u672c\u5730\u8986\u76d6\uff0c\u5728Nacos\u9879\u76ee\u4e2dIssue\u4e2d\u5f97\u5230\u8bc1\u5b9e\uff0c\u4f3c\u4e4e\u5b98\u65b9\u4e5f\u6ca1\u6709\u8fd9\u79cd\u6253\u7b97\u3002\u503c\u5f97\u4e00\u63d0\u7684\u662f\uff0c\u5373\u4f7f\u901a\u8fc7\u547d\u4ee4\u884c\u6307\u5b9a\u7684\u53c2\u6570\uff0c\u4e5f\u4e0d\u80fd\u8986\u76d6\u8fdc\u7a0b\u914d\u7f6e\u3002\\r\\n\\r\\n\u5173\u4e8e\u8be5\u95ee\u9898\u7684Issue:\\r\\n\\r\\n- [Unable to override datasource](https://github.com/alibaba/nacos/issues/4190)\\r\\n- [\u5728\u4f7f\u7528\u547d\u4ee4\u884c\u53c2\u6570(-Dserver.port = 9000)\u542f\u52a8\u88abnacos\u7ba1\u7406\u7684\u670d\u52a1\u5ba2\u6237\u7aef\u65f6,\u53d1\u73b0\u547d\u4ee4\u884c\u53c2\u6570\u6ca1\u6709\u751f\u6548](https://github.com/alibaba/nacos/issues/3510)\\r\\n- [nacos\u662f\u5426\u5b58\u5728\u7c7b\u4f3cspringcloudconfig\u7684allow-override\u7b49\u672c\u5730\u63a7\u5236\u6743\u9650\u53c2\u6570\uff1f\u6216\u8005\u662f\u5426\u652f\u6301\u8fd9\u4e2a\u53c2\u6570](https://github.com/alibaba/nacos/issues/3981)\\r\\n\\r\\n\\r\\n## \u56db\u3001\u8e29\u8fc7\u7684\u5751\\r\\n\\r\\n\u5728\u4e00\u6b21\u5f00\u53d1\u8fc7\u7a0b\u4e2d\uff0c\u6211\u4eec\u5e0c\u671b\u670d\u52a1(serviceA)\u7684\u67d0\u4e9b\u8282\u70b9\u7684\u914d\u7f6e\u4e0e\u5176\u4ed6\u8282\u70b9\u914d\u7f6e\u4e0d\u540c\uff0c\u521a\u5f00\u59cb\u7684\u60f3\u6cd5\u662f\u5728\u542f\u52a8\u547d\u4ee4\u884c\u52a0\u5165\u53c2\u6570 `spring.application.name=serviceB`\uff0c\u7136\u540e\u5728\u914d\u7f6e\u4e2d\u5fc3 `nacos`  \u4e2d\u590d\u5236\u4e00\u4efdserviceA\u7684\u914d\u7f6e\u547d\u540d\u4e3a service B\u3002\u4f46\u662f\u5b9e\u9645\u6d4b\u8bd5\u4e2d\uff0c\u4e0d\u80fd\u4fee\u6539 application.name \u7684\u503c\uff0c\u56e0\u4e3a\u53c2\u4e0e\u5230\u4e00\u4e9b\u4e1a\u52a1\u914d\u7f6e\u3002\\r\\n\\r\\n\u63a5\u7740\u6211\u4eec\u60f3\u76f4\u63a5\u5728\u547d\u4ee4\u884c\u4e2d\u52a0\u5165\u533a\u522b\u4e8e\u5176\u4ed6\u8282\u70b9\u7684\u53c2\u6570\uff0c\u5e0c\u671b\u80fd\u591f\u8986\u76d6\u8fdc\u7a0b\u7684\u914d\u7f6e\uff0c\u4f46\u524d\u9762\u4e5f\u8bf4\u8fc7\uff0c\u547d\u4ee4\u884c\u7684\u914d\u7f6e\u65e0\u6cd5\u8986\u76d6\u8fdc\u7a0bNacos\u914d\u7f6e\uff0c\u4e14Nacos\u6ca1\u6709\u63d0\u4f9b\u652f\u6301\u8986\u76d6\u7684\u5f00\u5173\uff0c\u6240\u4ee5\u4e5f\u6ca1\u80fd\u8fbe\u5230\u6211\u4eec\u9884\u671f\u7684\u7ed3\u679c\u3002\\r\\n\\r\\n\u5b9e\u9645\u6d4b\u8bd5\u7684\u7ed3\u679c\uff0c\u914d\u7f6e\u4f18\u5148\u7ea7\uff1a**nacos\u4e0a\u7684\u914d\u7f6e > \u547d\u4ee4\u884c\u914d\u7f6e > system env > classpath:application.yml > classpath:bootstrap.yml**\\r\\n\\r\\n\u6700\u540e\u6211\u4eec\u53d1\u73b0nacos\u652f\u6301\u6307\u5b9a\u670d\u52a1\u914d\u7f6e\uff0c\u4ee5\u53ca\u670d\u52a1\u53d1\u73b0\u7684\u540d\u79f0\uff0c\u8fd9\u4e9b\u914d\u7f6e\u662f\u5728 `bootstap.yml` \u6587\u4ef6\u4e2d\u6307\u5b9a\uff0c\u9ed8\u8ba4\u503c\u662f `spring.application.name`\u3002\u5b9e\u9645\u6d4b\u8bd5\u7ed3\u679c\uff0c\u901a\u8fc7\u547d\u4ee4\u884c\u53ef\u4ee5\u8986\u76d6\u8be5\u6587\u4ef6\u4e2d\u7684\u914d\u7f6e\uff0c\u8fd9\u6837\u6b63\u597d\u80fd\u591f\u6ee1\u8db3\u6211\u4eec\u7684\u9700\u6c42\uff1a\u4e0d\u4fee\u6539application.name\uff0c\u53c8\u53ef\u4ee5\u4f7f\u90e8\u5206\u8282\u70b9\u7684\u914d\u7f6e\u533a\u522b\u4e8e\u5176\u4ed6\u8282\u70b9\u3002\\r\\n\\r\\n```shell\\r\\njava -jar ./app.jar --spring.profiles.active=local --spring.cloud.nacos.config.name=serviceB --spring.cloud.nacos.discovery.service=serviceB\\r\\n```\\r\\n\\r\\n\\r\\n## \u4e94\u3001\u53c2\u8003\u8d44\u6599\\r\\n\\r\\n- [SpringBoot Externalized Configuration](https://docs.spring.io/spring-boot/docs/2.2.9.RELEASE/reference/htmlsingle/#boot-features-external-config)\\r\\n- [Nacos \u914d\u7f6e\u4e2d\u5fc3\uff0c\u53ef\u914d\u7f6e\u9879](https://github.com/alibaba/spring-cloud-alibaba/wiki/Nacos-config-en#more-information-about-nacos-config-starter-configurations)\\r\\n- [Nacos\u6ce8\u518c\u4e2d\u5fc3\uff0c\u53ef\u914d\u7f6e\u9879](https://github.com/alibaba/spring-cloud-alibaba/wiki/Nacos-discovery-en#more-information-about-nacos-discovery-starter-configurations)"},{"id":"jvm-dump-file-analysis-experience","metadata":{"permalink":"/blog/jvm-dump-file-analysis-experience","source":"@site/blog\\\\2022-03-12-\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b.md","title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","description":"\u4e00\u3001\u80cc\u666f","date":"2022-03-12T00:00:00.000Z","formattedDate":"2022\u5e743\u670812\u65e5","tags":[{"label":"JVM","permalink":"/blog/tags/jvm"}],"truncated":false,"authors":[],"frontMatter":{"slug":"jvm-dump-file-analysis-experience","title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","tags":["JVM"]},"prevItem":{"title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","permalink":"/blog/springboot-config-priority"}},"content":"## \u4e00\u3001\u80cc\u666f\\n\\n\u4eca\u5929\u4e0b\u5348\uff0c\u6b63\u9163\u7545\u6dcb\u6f13\u7684\u642c\u7816\uff0c\u7a81\u7136\u8fd0\u7ef4\u540c\u4e8b\u5728\u7fa4\u91cc\u901a\u77e5\uff0c\u6838\u5fc3\u670d\u52a1\u67d0\u4e2a\u8282\u70b9\u5185\u5b58\u5f02\u5e38\uff0c\u670d\u52a1\u5047\u6b7b\u3002\u795e\u7ecf\u4e00\u4e0b\u5b50\u7d27\u5f20\u8d77\u6765\uff0c\u8d76\u7d27\u8dd1\u5230\u8fd0\u7ef4\u90a3\u8fb9\u89c2\u5bdf\u73b0\u8c61\u3002\\n\\n\u89c2\u5bdf\u7684\u7ed3\u679c\u662f\u670d\u52a1\u5185\u5b58\u6ea2\u51fa\uff0c\u8be5\u670d\u52a1\u662f\u6838\u5fc3\u670d\u52a1\uff0c\u5206\u914d\u4e865G\u5185\u5b58\u3002\u8fd0\u7ef4\u5728\u8f6c\u5b58\u5feb\u7167\u540e\uff0c\u7acb\u523b\u91cd\u542f\u670d\u52a1\u540e\u6b63\u5e38\u3002\u5728\u63a5\u4e0b\u6765\u7684\u4e00\u6bb5\u65f6\u95f4\u91cc\uff0c\u53e6\u4e00\u53f0\u670d\u52a1\u8282\u70b9\u4e5f\u53d1\u751f\u4e86\u540c\u6837\u7684\u60c5\u51b5\u3002\\n\\n## \u4e8c\u3001\u5206\u6790\u8fc7\u7a0b\\n\\n\u8fd9\u4e2a\u670d\u52a1\u662f\u53e6\u5916\u4e00\u4e2a\u540c\u4e8b\u8d1f\u8d23\u5f00\u53d1\u7684\uff0c\u672c\u7740\u5b66\u4e60\u7684\u6001\u5ea6\uff0c\u5728\u62ff\u5230\u8fd0\u7ef4\u8f6c\u5b58\u7684dump\u6587\u4ef6\u540e\uff0c\u5c31\u51c6\u5907\u5c1d\u8bd5\u7740\u5206\u6790\u4e0b\u95ee\u9898\uff0c\u7531\u4e8e\u4e4b\u524d\u6ca1\u6709\u7c7b\u4f3c\u7684\u7ecf\u5386\uff0c\u4e8e\u662f\u5148\u5728\u7f51\u4e0a\u67e5\u4e86\u4e0b\u4e00\u822c\u600e\u4e48\u5206\u6790\u7c7b\u4f3c\u7684\u95ee\u9898\u3002\\n\\n\u9996\u5148\u5c1d\u8bd5\u4f7f\u7528MAT(Memory Analyzer)\u5de5\u5177\u8fdb\u884c\u5206\u6790\uff0c\u4e0b\u8f7d\u540e\u5c31\u51c6\u5907\u8f7d\u5165dump\u6587\u4ef6\uff0c\u5f88\u4e0d\u5e78\u7531\u4e8edump\u6587\u4ef6\u8fc7\u5927\uff0c\u8f7d\u5165\u5931\u8d25\u4e86\uff0c\u4e8e\u662f\u8c03\u5927\u4e86\u5185\u5b58\u5927\u5c0f\uff0c\u5c1d\u8bd5\u518d\u6b21\u8f7d\u5165\uff0c\u4f46\u6b64\u65f6\u8fd9\u4e2a\u6587\u4ef6\u4e0d\u518d\u5c1d\u8bd5\u91cd\u65b0\u8f7d\u5165\uff0c\u76f4\u63a5\u63d0\u793a\u8f7d\u5165\u5931\u8d25\u3002\\n\\n\u5148\u4e0d\u7ea0\u7ed3\u5de5\u5177\u7684\u95ee\u9898\uff0c\u7136\u540e\u7f51\u4e0a\u8bf4JDK\u81ea\u5e26\u7684`jvisualvm`\u4e5f\u53ef\u4ee5\u7528\u6765\u5206\u6790dump\u6587\u4ef6, \u4f46\u4e5f\u9047\u5230\u4e86\u540c\u6837\u5185\u5b58\u4e0d\u8db3\u7684\u95ee\u9898\uff0c\u518d\u5c1d\u8bd5\u4fee\u6539`jvisualvm`\u7684\u5185\u5b58\u9650\u5236\u540e, \u6210\u529f\u8f7d\u5165\u4e86\u3002\\n\\n\u770b\u5230\u7684\u754c\u9762\u662f\u8fd9\u6837\u7684\uff0c\u5f88\u660e\u663e\u770b\u5230char[]\u5360\u7528\u4e86\u8fd170%\u7684\u5185\u5b58\uff0c\u63a5\u8fd14G\uff0c\u8fd9\u592a\u4e0d\u6b63\u5e38\u4e86\uff0c\u70b9\u8fdb\u53bb\u770b\u5bf9\u5e94\u7684\u5b9e\u4f8b(\u52a0\u8f7d\u7684\u975e\u5e38\u6162\uff0c\u9700\u8981\u8010\u5fc3)\u3002\\n\\n![](http://file.huhan.tech/images/202205291114190.png)\\n\\n\u5728\u5b9e\u4f8b\u6570\u754c\u9762\u4e2d\u770b\u5230\u5b9e\u4f8b\u6570\u8fbe\u5230\u4e86\u5343\u4e07\u7ea7\uff0c\u5927\u90e8\u5206\u90fd\u662f\u4e00\u4e9b\u6587\u4ef6\u7684\u8def\u5f84\u5b57\u7b26\u4e32\u4fe1\u606f\u3002\u5728\u4e1a\u52a1\u4e2d\uff0c\u6211\u4eec\u4f1a\u751f\u6210\u5f88\u591a\u4e34\u65f6\u6587\u4ef6\uff0c\u7136\u540e\u8fd9\u4e9b\u4e34\u65f6\u6587\u4ef6\u4f1a\u5220\u9664\uff0c\u8fd9\u91cc\u9762\u5927\u90e8\u5206\u4fdd\u5b58\u7684\u662f\u8fd9\u4e9b\u4e34\u65f6\u6587\u4ef6\u8def\u5f84\u3002\\n\\n![](http://file.huhan.tech/images/202205291115665.png)\\n\\n\u5230\u8fd9\u91cc\u5bfc\u81f4\u5185\u5b58\u6cc4\u9732\u7684\u539f\u56e0\u4f3c\u4e4e\u627e\u5230\u4e86\uff0c\u4f46\u597d\u50cf\u53c8\u8fd8\u4e0d\u591f\uff0c\u662f\u4ec0\u4e48\u539f\u56e0\u5bfc\u81f4\u8fd9\u4e9b\u4e34\u65f6\u53d8\u91cf\u6ca1\u6709\u88ab\u56de\u6536\u5462\u3002\\n\\n\u56de\u5230\u5bb6\u540e\uff0c\u8fd8\u662f\u60f3\u7740\u8fd9\u4e2a\u4e8b\u60c5\uff0c\u4e8e\u662f\u53c8\u5f00\u59cb\u7814\u7a76\u8d77\u6765\uff0c\u8fd9\u4e2a\u65f6\u5019\u60f3\u8d77\u6765\u53ef\u4ee5\u518d\u7528MAT\u8bd5\u7740\u5206\u6790\u4e0b\uff0c\u6bd5\u7adf\u636e\u8bf4\u5de5\u5177\u5f88\u5f3a\u5927\u3002\u91cd\u542f\u4e86\u7535\u8111\u4e4b\u540e\uff0c\u7ecf\u8fc7\u6f2b\u957f\u7684\u7b49\u5f85\uff0c\u8f7d\u5165\u6210\u529f\u4e86(\u679c\u7136\u91cd\u542f\u80fd\u89e3\u51b3\u4e00\u5207\u95ee\u9898)\u3002\\n\\nMAT\u7684\u754c\u9762\u662f\u8fd9\u6837\u7684\uff0c\u91cc\u9762\u5305\u542b\u7684\u4fe1\u606f\u6bd4\u8f83\u591a\uff0c\u5bf9\u4e8e\u6211\u8fd9\u4e2a\u83dc\u9e1f\u6765\u8bf4\uff0c\u786e\u5b9e\u4e00\u4e0b\u5b50\u4e0d\u77e5\u9053\u770b\u54ea\u91cc\u3002\\n\u90a3\u5c31\u4e00\u4e2a\u4e2a\u6162\u6162\u770b\u5427\uff0cHistogram\u91cc\u9762\u7684\u4e0e\u4f7f\u7528`jvisualvm`\u4e2d\u770b\u5230\u7684\u4fe1\u606f\u662f\u76f8\u540c\u7684\u3002\\n\\n![](http://file.huhan.tech/images/202205291115133.png)\\n\\n\u63a5\u4e0b\u6765\u8fdb\u5165\u5230`Dominator Tree`\u89c6\u56fe, \u5217\u51fa\u5f53\u524d\u5b58\u6d3b\u7684\u5bf9\u8c61\u7684\u5185\u5b58\u5927\u5c0f\uff0c\u8fd9\u770b\u8d77\u6765\u50cf\u662f\u6211\u9700\u8981\u5173\u6ce8\u7684\u91cd\u70b9\u3002\u7136\u540e\u67e5\u4e86\u4e0b\u8fd9\u4e2a\u7c7b `java.io.DeleteOnExitHook`  \u4e0e \u5185\u5b58\u6cc4\u9732\u7684\u76f8\u5173\u95ee\u9898\u3002\\n\\n![](http://file.huhan.tech/images/202205291116984.png)\\n\\n\u8fd9\u4e2a\u95ee\u9898\u5728\u4e0b\u9762\u4e24\u4e2a\u94fe\u63a5\u4e2d\u7ed9\u51fa\u4e86\u8bf4\u660e\uff0c\u5927\u6982\u610f\u601d\u662f\u5728\u5220\u9664\u6587\u4ef6\u4f7f\u7528 `File.deleteOnExit()` \u65b9\u6cd5\u65f6\uff0c\u5e76\u4e0d\u662f\u7acb\u523b\u5220\u9664\u6587\u4ef6\uff0c\u800c\u662f\u5c06\u8be5\u6587\u4ef6\u8def\u5f84\u7ef4\u62a4\u5728\u7c7bDeleteOnExit\u7684\u4e00\u4e2aLinkedHashSet\u4e2d\uff0c\u6700\u540e\u5728JVM\u5173\u95ed\u7684\u65f6\u5019\uff0c\u624d\u4f1a\u53bb\u5220\u9664\u8fd9\u91cc\u9762\u7684\u6587\u4ef6\uff0c\u8fd9\u4e2a\u65b9\u6cd5\u4e0d\u80fd\u7528\u4e8e\u957f\u65f6\u95f4\u8fd0\u884c\u7684\u670d\u52a1\u3002\\nhttps://stackoverflow.com/questions/40119188/memory-leak-on-deleteonexithook\\nhttps://bugs.openjdk.java.net/browse/JDK-6664633\\n\\n\u4e0a\u9762\u7684\u63cf\u8ff0\uff0c\u901a\u8fc7\u6e90\u7801\u548cJDK\u6587\u6863\u4e5f\u90fd\u5f97\u5230\u4e86\u8bc1\u660e\u3002\\n\\n```java\\n// java.io.File\\n// Requests that the file or directory denoted by this abstract pathname be deleted when the virtual machine terminates.\\npublic void deleteOnExit() {\\n\\tSecurityManager security = System.getSecurityManager();\\n\\tif (security != null) {\\n\\t\\tsecurity.checkDelete(path);\\n\\t}\\n\\tif (isInvalid()) {\\n\\t\\treturn;\\n\\t}\\n\\tDeleteOnExitHook.add(path);\\n}\\n\\n// java.io.DeleteOnExitHook\\nprivate static LinkedHashSet<String> files = new LinkedHashSet<>();\\n\\nstatic synchronized void add(String file) {\\n\\tif(files == null) {\\n\\t\\t// DeleteOnExitHook is running. Too late to add a file\\n\\t\\tthrow new IllegalStateException(\\"Shutdown in progress\\");\\n\\t}\\n\\n\\tfiles.add(file);\\n}\\n```\\n\\n\\n## \u4e09\u3001\u7ed3\u8bba\\n\\n\u95ee\u9898\u5b9a\u4f4d\u4e8e`File.deleteOnExit()`\u65b9\u6cd5\u7684\u8c03\u7528\uff0c\u5bfc\u81f4\u5185\u5b58\u6cc4\u6f0f\u3002\u8c03\u7528\u8be5\u65b9\u6cd5\u53ea\u4f1a\u5c06\u9700\u8981\u5220\u9664\u6587\u4ef6\u7684\u8def\u5f84\uff0c\u7ef4\u62a4\u5728\u7c7b`DeleteOnExit`\u7684\u4e00\u4e2aLinkedHashSet\u4e2d\uff0c\u5728JVM\u5173\u95ed\u65f6\uff0c\u624d\u4f1a\u53bb\u771f\u6b63\u6267\u884c\u5220\u9664\u6587\u4ef6\u64cd\u4f5c\u3002\u8fd9\u6837\u5bfc\u81f4`DeleteOnExitHook`\u8fd9\u4e2a\u5bf9\u8c61\u8d8a\u6765\u8d8a\u5927\uff0c\u6700\u7ec8\u5185\u5b58\u6ea2\u51fa\u3002\\n\\n`File.delete()`\u4e0e `File.deleteOnExit()` \u7684\u533a\u522b\uff1a\\n\u5f53\u8c03\u7528delete()\u65b9\u6cd5\u65f6\uff0c\u76f4\u63a5\u5220\u9664\u6587\u4ef6\uff0c\u4e0d\u7ba1\u8be5\u6587\u4ef6\u662f\u5426\u5b58\u5728\uff0c\u4e00\u7ecf\u8c03\u7528\u7acb\u5373\u6267\u884c\\n\u5f53\u8c03\u7528deleteOnExit()\u65b9\u6cd5\u65f6\uff0c\u53ea\u662f\u76f8\u5f53\u4e8e\u5bf9deleteOnExit()\u4f5c\u4e00\u4e2a\u58f0\u660e\uff0c\u5f53\u7a0b\u5e8f\u8fd0\u884c\u7ed3\u675f\uff0cJVM\u7ec8\u6b62\u65f6\u624d\u771f\u6b63\u8c03\u7528deleteOnExit()\u65b9\u6cd5\u5b9e\u73b0\u5220\u9664\u64cd\u4f5c\u3002\\n\\n\u6211\u5199\u4e86\u4e0b\u9762\u8fd9\u4e2a\u6d4b\u8bd5\u65b9\u6cd5\uff0c\u5bf9\u6bd4 `delete()`\u548c`deleteOnExit()`\u7684\u533a\u522b\uff0c\u73b0\u8c61\u4f1a\u6bd4\u8f83\u660e\u663e\u3002\u4f7f\u7528`deleteOnExit`\u65f6\u662f\u5728\u6587\u4ef6\u5168\u90e8\u521b\u5efa\uff0cJVM\u5173\u95ed\u7684\u65f6\u5019\uff0c\u624d\u4e00\u4e2a\u4e2a\u5220\u9664\u6587\u4ef6\uff0c`delete`\u4f1a\u7acb\u523b\u5220\u9664\u6587\u4ef6\u3002(\u6240\u4ee5\u8fd9\u4e2a\u65b9\u6cd5\u7684\u4f7f\u7528\u573a\u666f\u662f\u600e\u6837\u7684\uff0c\u6211\u5c31\u4e0d\u592a\u6e05\u695a\u4e86)\\n```java\\npublic static void loopTest() throws IOException {\\n\\tString root = \\"D:\\\\\\\\C_Temp\\\\\\\\files\\\\\\\\\\";\\n\\n\\tFile path = new File(root);\\n\\tif (!path.exists()) {\\n\\t\\tpath.mkdirs();\\n\\t}\\n\\tint i = 0;\\n\\twhile (i < 40000) {\\n\\t\\tFile file = new File(path, \\"Hello-\\" + i + \\".txt\\");\\n\\t\\tfile.createNewFile();\\n\\t\\tfile.delete();\\n//            file.deleteOnExit();\\n\\t\\ti++;\\n\\t}\\n}\\n```\\n\\n## \u56db\u3001\u6536\u83b7\\n\\n\u672c\u6b21\u6392\u67e5\u7ecf\u5386\u6700\u5927\u7684\u6536\u83b7\u5c31\u662f\u5c1d\u8bd5\u5229\u7528\u5de5\u5177\u5206\u6790dump\u6587\u4ef6\uff0c\u4ee5\u524d\u5bf9\u8fd9\u79cd\u90fd\u662f\u671b\u800c\u5374\u6b65\uff0c\u611f\u89c9\u5f88\u96be\u3002\u4f46\u8fd9\u6b21\u5e26\u7740\u95ee\u9898\u53bb\u5206\u6790\u3001\u601d\u8003\uff0c\u8fd9\u6837\u4e0b\u6765\u4e5f\u4e0d\u7b97\u8fc7\u4e8e\u590d\u6742\u3002\u6709\u4e9b\u95ee\u9898\u4e0d\u662f\u95ee\u9898\u672c\u8eab\u96be\uff0c\u662f\u81ea\u5df1\u628a\u5b83\u60f3\u5f97\u5f88\u96be\u3002\\n\\n\u4e0b\u9762\u662f\u672c\u6b21\u7684\u4e00\u4e9b\u601d\u8003\u548c\u8e29\u8fc7\u7684\u5751\uff0c\u4ee5\u4f5c\u5907\u5fd8\u3002\\n\\n**1. \u83b7\u53d6dump\u6587\u4ef6\u6709\u4e24\u79cd\u65b9\u6cd5**\\n\\n1)\u901a\u8fc7 `jmap` \u5de5\u5177\u751f\u6210\u53ef\u4ee5\u751f\u6210\u4efb\u610fJava\u8fdb\u7a0b\u7684dump\u6587\u4ef6\\n```shell\\n# \u5148\u627e\u5230PID\\nps -ef | grep java\\n\\n# jmap \u8f6c\u5b58\u5feb\u7167\\njmap -dump:format=b,file=/opt/dump/test.dump {PID}\\n```\\n\\n2)\u901a\u8fc7\u914d\u7f6eJVM\u542f\u52a8\u53c2\u6570\\n```shell\\n#  \u5f53\u7a0b\u5e8f\u51fa\u73b0OutofMemory\u65f6\uff0c\u5c06\u4f1a\u5728\u76f8\u5e94\u7684\u76ee\u5f55\u4e0b\u751f\u6210\u4e00\u4efddump\u6587\u4ef6\uff0c\u5982\u679c\u4e0d\u6307\u5b9a\u9009\u9879HeapDumpPath\u5219\u5728\u5f53\u524d\u76ee\u5f55\u4e0b\u751f\u6210dump\u6587\u4ef6\\n-XX:+HeapDumpOnOutOfMemoryError -XX:HeapDumpPath=/opt/dumps\\n```\\n\\n![](http://file.huhan.tech/images/202205291116514.png)\\n\\n**2. MAT\u9700\u8981JDK11\u624d\u80fd\u8fd0\u884c**\\n\\n\u89e3\u51b3\u529e\u6cd5\u662f\uff0c\u6253\u5f00MAT\u7684\u5b89\u88c5\u76ee\u5f55\uff0c\u6709\u4e00\u4e2a\u914d\u7f6e\u6587\u4ef6MemoryAnalyzer.ini\u3002\u6253\u5f00\u8fd9\u4e2a\u6587\u4ef6\uff0c\u5728\u6587\u4ef6\u4e2d\u6307\u5b9aJDK\u7248\u672c\u5373\u53ef\u3002\u65b0\u589e\u4e24\u884c\u914d\u7f6e\uff1a\\n```shell\\n-vm D:/jdkPath/bin/javaw.exe\\n```\\n\\n**3. \u5728\u4f7f\u7528jvisualvm\u5206\u6790\u5927\u7684dump\u6587\u4ef6\u65f6\uff0c\u5806\u67e5\u5668\u4f7f\u7528\u7684\u5185\u5b58\u4e0d\u8db3**\\n\\n\u4fee\u6539JAVA_HOME/lib/visualvm/etc/visualvm.conf\u6587\u4ef6\u4e2d visualvm_default_options=\\"-J-client -J-Xms24 -J-Xmx256m\\"\uff0c\u7136\u540e\u91cd\u542fjvisualVM\u5373\u53ef\\n\\n**4. MAT\u4fee\u6539\u5185\u5b58\u7a7a\u95f4**\\n\\n\u5206\u6790\u5806\u8f6c\u50a8\u6587\u4ef6\u9700\u8981\u6d88\u8017\u5f88\u591a\u7684\u5806\u7a7a\u95f4\uff0c\u4e3a\u4e86\u4fdd\u8bc1\u5206\u6790\u7684\u6548\u7387\u548c\u6027\u80fd\uff0c\u5728\u6709\u6761\u4ef6\u7684\u60c5\u51b5\u4e0b\uff0c\u5efa\u8bae\u5206\u914d\u7ed9 MAT \u5c3d\u53ef\u80fd\u591a\u7684\u5185\u5b58\u8d44\u6e90\u3002\u4e24\u79cd\u65b9\u5f0f\u5206\u914d\u5185\u5b58\u8d44\u6e90\u7ed9 MAT\uff1a\\n1\uff09\u4fee\u6539\u542f\u52a8\u53c2\u6570 MemoryAnalyzer.exe -vmargs -Xmx4g\\n2\uff09\u7f16\u8f91\u6587\u4ef6 MemoryAnalyzer.ini \u6dfb\u52a0 -vmargs \u2013 Xmx4g\\n\\n\u8fd9\u91cc\u4e5f\u5217\u4e00\u4e2a\u4ee3\u529e\u9879\\n- \u5b66\u4e60`MAT`\u5de5\u5177\u7684\u4f7f\u7528\\n\\n\\n\u53c2\u8003\u7684\u4e00\u4e9b\u6587\u7ae0\uff1a\\n- jvisualvm\u5206\u6790\uff1ahttps://zhuanlan.zhihu.com/p/163774290\\n- MAT\u5b9a\u4f4d\u5927\u5bf9\u8c61\uff1ahttps://www.cnblogs.com/rb2010/p/14741674.html\\n- MAT\u8be6\u7ec6\uff1ahttps://blog.csdn.net/Jin_Kwok/article/details/80326088\\n- https://www.jianshu.com/p/82b25cf8cfde"}]}')}}]);